Patch-File "app\api\marketplace\order\route.ts" {
  param($content)

  if ($content -notmatch "whatsapp-notifications") {
    $content = $content.Replace(
      "import { generatePixPayload, sanitizeTxid } from '@/lib/pix'",
      "import { generatePixPayload, sanitizeTxid } from '@/lib/pix'`r`nimport { notifyNewOrder } from '@/lib/whatsapp-notifications'"
    )
  }

  if ($content -notmatch "notifyNewOrder\(supabaseAdmin") {
    $needle = "    if (itemsError) throw itemsError"
    $insert = @'
    if (itemsError) throw itemsError

    try {
      await notifyNewOrder(supabaseAdmin, {
        company,
        order: {
          id: order.id,
          company_id: companyId,
          nome: String(cliente.nome).trim(),
          telefone,
          produto: resumo,
          itens_resumo: resumo,
          valor_total: total,
          preco_estimado: total,
        },
        cliente,
        total,
        resumo,
      })
    } catch (notifyError) {
      console.error('[Orçaly WhatsApp] Falha ao notificar novo pedido:', notifyError)
    }
'@
    $content = $content.Replace($needle, $insert)
  }

  return $content
}

