Patch-File "app\painel\orcamento\[id]\page.tsx" {
  param($content)

  if ($content -notmatch "notificarStatusPedido") {
    $needle = "  async function atualizarStatus(novoStatus: string) {"
    $insert = @'
  async function notificarStatusPedido(novoStatus: string) {
    try {
      const { data: sessionData } = await supabase.auth.getSession()
      const token = sessionData.session?.access_token
      if (!token || !pedido?.id) return

      await fetch('/api/whatsapp/order-status', {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          order_id: pedido.id,
          status: novoStatus,
          source: 'pedido',
        }),
      })
    } catch (error) {
      console.error('[Orçaly WhatsApp] Falha ao avisar status:', error)
    }
  }

  async function atualizarStatus(novoStatus: string) {
'@
    $content = $content.Replace($needle, $insert)
  }

  if ($content -notmatch "await notificarStatusPedido\(novoStatus\)") {
    $content = $content.Replace(
      "    setPedido({ ...pedido, status: novoStatus })`r`n    setMensagem('Status atualizado.')",
      "    setPedido({ ...pedido, status: novoStatus })`r`n    await notificarStatusPedido(novoStatus)`r`n    setMensagem('Status atualizado.')"
    )
  }

  return $content
}

Patch-File "app\painel\producao\page.tsx" {
  param($content)

  if ($content -notmatch "notificarStatusProducao") {
    $needle = "  async function updateOrder(id: string, status: string) {"
    $insert = @'
  async function notificarStatusProducao(id: string, status: string) {
    try {
      const { data: sessionData } = await supabase.auth.getSession()
      const token = sessionData.session?.access_token
      if (!token) return

      await fetch('/api/whatsapp/order-status', {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          production_order_id: id,
          status: statusLabel(status),
          source: 'producao',
        }),
      })
    } catch (error) {
      console.error('[Orçaly WhatsApp] Falha ao avisar produção:', error)
    }
  }

  async function updateOrder(id: string, status: string) {
'@
    $content = $content.Replace($needle, $insert)
  }

  if ($content -notmatch "await notificarStatusProducao\(id, status\)") {
    $content = $content.Replace(
      "    if (error) setErro(error.message)`r`n    else await carregar()",
      "    if (error) setErro(error.message)`r`n    else {`r`n      await notificarStatusProducao(id, status)`r`n      await carregar()`r`n    }"
    )
  }

  return $content
}

